3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const aliveKeys = new Set(cells.map(keyOf));
16	  const liveNeighborCounts = new Map<string, { cell: Cell; count: number }>();
17	  for (const cell of cells) {
18	    for (const neighbor of neighborsOf(cell)) {
19	      const k = keyOf(neighbor);
20	      const entry = liveNeighborCounts.get(k);
21	      if (entry) entry.count += 1;
22	      else liveNeighborCounts.set(k, { cell: neighbor, count: 1 });
23	    }
24	  }
25	  const result: Cell[] = [];
26	  for (const cell of cells) {
27	    const count = liveNeighborCounts.get(keyOf(cell))?.count ?? 0;
28	    if (count === 2 || count === 3) result.push(cell);
29	  }
30	  for (const { cell, count } of liveNeighborCounts.values()) {
31	    if (count === 3 && !aliveKeys.has(keyOf(cell))) result.push(cell);
32	  }
