4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Vertical line of 3 cells - center cell (0,1) has 2 live neighbors and survives
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    // Center (1,1) has 4 live neighbors at the corners, so it dies
21	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
