export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(keyOf));
  const liveNeighborCounts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = keyOf(neighbor);
      const entry = liveNeighborCounts.get(k);
      if (entry) entry.count += 1;
      else liveNeighborCounts.set(k, { cell: neighbor, count: 1 });
    }
  }
  const result: Cell[] = [];
  for (const [k, { cell, count }] of liveNeighborCounts) {
    if (count === 3 || (count === 2 && aliveKeys.has(k))) result.push(cell);
  }
  return result;
}
